const body = $input.first().json;
const transcript = body.transcript || body.query || '';

if (!transcript || transcript.length < 2) {
  throw new Error('transcript/query fehlt oder zu kurz');
}

return [{ json: {
  transcript: transcript,
  session_id: body.session_id || `vb-${Date.now()}`,
  tenant_slug: body.tenant_slug || 'eppcom',
  tenant_id_direct: body.tenant_id || null,
  top_k: body.top_k || 5,
  min_similarity: body.min_similarity || 0.3,
  model: body.model || 'qwen2.5:7b-eppcom',
  started_at: Date.now()
}}];

const tenant = $input.first().json;
const input = $('Validate & Prepare').first().json;
const tid = input.tenant_id_direct || (tenant && tenant.id ? tenant.id : null);
if (!tid) {
  throw new Error('Tenant nicht gefunden: ' + input.tenant_slug);
}
return [{ json: { ...input, tenant_id: tid } }];

const embeddings = $input.first().json.embeddings;
if (!embeddings || !embeddings[0]) {
  throw new Error('Embedding-Generierung fehlgeschlagen');
}
const prev = $('Merge Tenant ID').first().json;
return [{ json: {
  ...prev,
  embedding: JSON.stringify(embeddings[0]),
  embed_time_ms: Date.now() - prev.started_at
}}];

const chunks = $input.all().map(i => i.json);
const prev = $('Extract Embedding').first().json;

// Build RAG context from top chunks
let context = '';
if (chunks.length > 0 && chunks[0].content) {
  context = chunks
    .filter(c => c.content)
    .map((c, i) => `[Quelle: ${c.source_name || 'Unbekannt'}, Relevanz: ${(c.similarity * 100).toFixed(0)}%]\n${c.content}`)
    .join('\n\n---\n\n');
} else {
  context = 'Keine relevanten Dokumente gefunden.';
}

const ragTimeMs = Date.now() - prev.started_at;

return [{ json: {
  transcript: prev.transcript,
  session_id: prev.session_id,
  tenant_id: prev.tenant_id,
  model: prev.model,
  context: context,
  chunk_count: chunks.filter(c => c.content).length,
  started_at: prev.started_at,
  rag_time_ms: ragTimeMs
}}];

