const llmResponse = $input.first().json;
const prev = $('Build LLM Context').first().json;

const totalTimeMs = Date.now() - prev.started_at;
const llmTimeMs = totalTimeMs - prev.rag_time_ms;

const responseText = llmResponse.response || 'Entschuldigung, ich konnte keine Antwort generieren.';

// Clean up response - remove thinking tags if present
let cleanResponse = responseText
  .replace(/<think>[\s\S]*?<\/think>/g, '')
  .replace(/<\/no_think>/g, '')
  .trim();

return [{ json: {
  status: 'success',
  answer: cleanResponse,
  response: cleanResponse,
  session_id: prev.session_id,
  metrics: {
    rag_time_ms: prev.rag_time_ms,
    llm_time_ms: llmTimeMs,
    total_time_ms: totalTimeMs,
    chunks_found: prev.chunk_count,
    model: prev.model
  }
}}];
